import React from "react";
import '../../components/Components.css';

export default function TimelineTab({ caseData }) {
  const events = [];

  if (caseData?.start_date) {
    events.push({ date: caseData.start_date, label: `Case opened: "${caseData.title}"`, color: "#4f46e5" });
  }
  if (caseData?.leadInvestigators?.length) {
    events.push({ date: caseData.start_date, label: `Lead Investigator assigned: ${caseData.leadInvestigators.join(", ")}`, color: "#34d399" });
  }
  if (caseData?.members?.length) {
    events.push({ date: caseData.start_date, label: `${caseData.members.length} team member${caseData.members.length > 1 ? "s" : ""} assigned to case`, color: "#818cf8" });
  }
  if (caseData?.status === "Close" && caseData?.end_date) {
    events.push({ date: caseData.end_date, label: "Case closed", color: "#f87171" });
  }
  if (caseData?.status === "Archived") {
    events.push({ date: caseData.end_date || caseData.start_date, label: "Case archived", color: "#94a3b8" });
  }

  const formatDate = (d) =>
    d ? new Date(d).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }) : "—";

  return (
    <div className="timelineContainer">
      {events.length === 0 ? (
        <p style={{ color: "#475569", fontSize: "0.875rem" }}>No timeline events yet</p>
      ) : (
        events.map((event, i) => (
          <div key={i} className="timelineEntry">
            <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 0 }}>
              <div className="timelineDot" style={{ background: event.color }} />
              {i < events.length - 1 && (
                <div style={{ width: 2, flex: 1, background: "rgba(255,255,255,0.06)", minHeight: 24, marginTop: 4 }} />
              )}
            </div>
            <div style={{ paddingBottom: i < events.length - 1 ? "1.25rem" : 0 }}>
              <p className="timelineInfo">{event.label}</p>
              <span style={{ fontSize: "0.7rem", color: "#334155" }}>{formatDate(event.date)}</span>
            </div>
          </div>
        ))
      )}
    </div>
  );
}
